function setBaseMap(style){if(!map||!window.L)return;style=style||getAppSettings().mapStyle||'osm';if(baseTile){try{map.removeLayer(baseTile)}catch(e){}}if(hybridLabelLayer){try{map.removeLayer(hybridLabelLayer)}catch(e){hybridLabelLayer=null}}const opts={maxZoom:19,attribution:''};if(style==='topo')baseTile=L.tileLayer('https://{s}.tile.opentopomap.org/{z}/{x}/{y}.png',{maxZoom:17,attribution:'OpenTopoMap'}).addTo(map);else if(style==='sat'||style==='hybrid'){baseTile=L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',{maxZoom:19,attribution:'Esri'}).addTo(map);if(style==='hybrid'){hybridLabelLayer=L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,opacity:.22,attribution:'OSM Labels'}).addTo(map)}}else baseTile=L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',opts).addTo(map);saveAppSettings({mapStyle:style})}
function applyOverlayOptions(){if(!map||!window.L)return;const o=getAppOptions();if(o.hikingOverlay){if(!hikingLayer)hikingLayer=L.tileLayer('https://tile.waymarkedtrails.org/hiking/{z}/{x}/{y}.png',{maxZoom:18,opacity:.72,interactive:false,attribution:'Waymarked Trails'}).addTo(map)}else if(hikingLayer){try{map.removeLayer(hikingLayer)}catch(e){}hikingLayer=null}markers.forEach((m,i)=>{if(m.getElement())m.getElement().style.display=(o.showPins&&matchesFilters(trails[i]))?'':'none'});if(!o.showGPX&&trackLayer){try{map.removeLayer(trackLayer);map.removeLayer(trackOutlineLayer)}catch(e){}}if(!o.showKML&&driveLayer){try{map.removeLayer(driveLayer);map.removeLayer(driveOutlineLayer)}catch(e){}}}
function ensureMap(){if(mapReady)return true;if(!window.L){toast('Kartenbibliothek nicht geladen');return false}mapReady=true;document.body.classList.add('map-ready');map=L.map('map',{zoomControl:false,attributionControl:false,preferCanvas:true}).setView([32.75,-16.95],10);setBaseMap(getAppSettings().mapStyle||'osm');applyOverlayOptions();L.control.attribution({position:'bottomright'}).addTo(map);trails.forEach((t,i)=>{const c=coord(t);if(!c)return;const icon=L.divIcon({className:'',html:`<div class="pr-marker" data-i="${i}">PR${t.number}${isFavId(t.id)?'<span class="pr-fav-badge">★</span>':''}</div>`,iconSize:[36,36],iconAnchor:[18,18]});const m=L.marker(c,{icon}).addTo(map);m.on('click',()=>pinTap(i));markers.set(i,m)});setTimeout(()=>map.invalidateSize(),80);setTimeout(()=>map.invalidateSize(),450);return true}function openDetail(i){ensureMap();activeIndex=i;active=trails[i];populate(active);$('detailCard').classList.remove('hidden');setMode('detail');window.scrollTo({top:0,behavior:'instant'});setTimeout(()=>fitActive(),140)}function populate(t){$('detailTitle').textContent=`PR${t.number} · ${t.name}`;$('detailSub').textContent=t.region||'Madeira';const sm=getStatusMeta(t);$('statusDot').textContent=sm.symbol;$('statusDot').className='traffic '+sm.className;const tr=tracks[t.id]?.stats||{};$('detailFacts').innerHTML=`<div class="fact status-fact ${sm.className}"><span>Status</span><strong>${sm.symbol} ${stxt(t)}</strong></div><div class="fact"><span>Distanz</span><strong>${fmt(t.trackKm||t.distanceKm,' km')}</strong></div><div class="fact"><span>Dauer</span><strong>${esc(t.duration||'–')}</strong></div><div class="fact"><span>Anfahrt</span><strong>${fmt(t.driveMin,' min')}</strong></div><div class="fact"><span>Aufstieg</span><strong>${fmt(t.trackAscent||t.elevationGain||tr.ascent,' m')}</strong></div><div class="fact"><span>Höhe</span><strong>${fmt(t.minEle||tr.minEle,'')}–${fmt(t.maxEle||tr.maxEle,' m')}</strong></div>`;$('detailText').textContent=getDetailTextForMode(t);renderProfile(t);renderContext(t);renderLinks(t)}function getDetailTextForMode(t){const mode=localStorage.getItem('prx.detailTextMode.v373')||'off';const s150='Kurzer Orientierungstext zur Route mit Charakter, Gelände, Aussicht und wichtigstem Hinweis. Layouttest für kompakte Detailbereiche mit maximal 150 Zeichen.';const d280='Diese Route verbindet zentrale Eckdaten, Landschaftscharakter, besondere Abschnitte und Hinweise zur Planung. Der Text dient als Layouttest für die volle Detailkarte und zeigt, ob längere Beschreibungen ohne Unruhe lesbar bleiben und ob die Detailseite noch praxistauglich bleibt.';if(mode==='short150')return s150;if(mode==='detail280')return d280;if(mode==='both')return s150+'\n\n'+d280;return t.detailText280||t.shortText150||t.note||`Region ${t.region||'Madeira'}. GPX ${t.hasTrack?'vorhanden':'noch nicht vorhanden'}, KML-Anfahrt ${t.hasDrive?'vorhanden':'noch nicht vorhanden'}.`}
function renderProfile(t){const pts=tracks[t.id]?.points||[];const box=$('profile');if(!pts.length){box.innerHTML='<div style="padding:16px;color:rgba(255,255,255,.65);font-weight:800">Kein GPX-Höhenprofil vorhanden</div>';return}const eles=pts.map(p=>p[2]).filter(v=>Number.isFinite(+v));if(!eles.length){box.innerHTML='<div style="padding:16px;color:rgba(255,255,255,.65);font-weight:800">GPX ohne Höhendaten</div>';return}const min=Math.min(...eles),max=Math.max(...eles),w=600,h=130,pad=14;let arr=[];pts.forEach((p,idx)=>{const e=+p[2];if(Number.isFinite(e)){const x=pad+(idx/(pts.length-1))*(w-pad*2);const y=h-pad-((e-min)/(max-min||1))*(h-pad*2);arr.push([x,y])}});let d=arr.map((p,i)=>(i?'L':'M')+p[0].toFixed(1)+' '+p[1].toFixed(1)).join(' ');let area=d+` L ${w-pad} ${h-pad} L ${pad} ${h-pad} Z`;box.innerHTML=`<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><path d="${area}" fill="rgba(66,211,156,.18)"/><path d="${d}" fill="none" stroke="#42d39c" stroke-width="4"/><text x="16" y="24" fill="rgba(255,255,255,.75)" font-size="18" font-weight="700">${Math.round(min)}–${Math.round(max)} m</text></svg>`}
