function getTrip(){try{return Object.assign({start:'2026-06-22',end:'2026-07-05'},JSON.parse(localStorage.getItem(TRIP_KEY)||'{}'))}catch(e){return{start:'2026-06-22',end:'2026-07-05'}}}
function saveTrip(v){try{localStorage.setItem(TRIP_KEY,JSON.stringify(Object.assign(getTrip(),v)))}catch(e){}}
function daysBetween(start,end){const a=new Date(start+'T00:00:00'),b=new Date(end+'T00:00:00');if(!Number.isFinite(+a)||!Number.isFinite(+b)||b<a)return[];let out=[];for(let d=new Date(a);d<=b;d.setDate(d.getDate()+1)){out.push(new Date(d))}return out}
function openTrip(){const sh=ensureModal('tripSheet','settings-sheet trip-sheet');const tr=getTrip();const days=daysBetween(tr.start,tr.end);const today=Object.entries(poiState).filter(([k,v])=>v==='heute').length,later=Object.entries(poiState).filter(([k,v])=>v==='spaeter'||v==='später').length;sh.innerHTML=sheetHead('Reise','tripClose')+`<div class="settings-row"><strong>Reisezeitraum</strong><div class="date-row"><label>Start <input type="date" id="tripStart" value="${tr.start}"></label><label>Ende <input type="date" id="tripEnd" value="${tr.end}"></label></div><small>${days.length} Reisetage</small></div><div class="trip-days">${days.map((d,i)=>`<div class="day-card"><strong>Tag ${i+1}</strong><span>${d.toLocaleDateString('de-DE',{weekday:'short',day:'2-digit',month:'2-digit'})}</span><small>PR/POI später zuordnen</small></div>`).join('')}</div><div class="settings-row"><strong>Listen</strong><div class="diag-grid"><div><b>Heute POIs</b><span>${today}</span></div><div><b>Später POIs</b><span>${later}</span></div><div><b>PR-Favoriten</b><span>vorbereitet</span></div></div><button id="tripMaps">Google-Maps Heute öffnen</button></div>`;sh.classList.remove('hidden');$('tripClose').onclick=()=>sh.classList.add('hidden');$('tripStart').onchange=e=>{saveTrip({start:e.target.value});openTrip()};$('tripEnd').onchange=e=>{saveTrip({end:e.target.value});openTrip()};$('tripMaps').onclick=()=>openTodayRoute();setMode('trip')}
function copyText(txt){try{navigator.clipboard?.writeText(txt);toast('Kopiert')}catch(e){toast('Kopieren nicht möglich')}}
function buildShareSummary(){return `PR-Explorer Madeira 3.7.3\nPRs: ${trails.length}\nPOIs: ${POIS.length}\nGPX: ${Object.keys(tracks).length}\nKML: ${Object.keys(drives).length}\nFilter: ${filterSummary()}`}
